import React, { useState } from 'react';
import { View, Text, Button } from 'react-native';
import { InAppBilling } from 'react-native-iap';

const purchaseItems = [
  {
    productId: 'com.example.product1',
    title: 'Product 1',
    description: 'Description for Product 1',
    price: '$0.99'
  },
  {
    productId: 'com.example.product2',
    title: 'Product 2',
    description: 'Description for Product 2',
    price: '$1.99'
  }
];

const PaymentModule = () => {
  const [loading, setLoading] = useState(false);
  const [purchaseResult, setPurchaseResult] = useState(null);

  const requestPurchase = async (productId) => {
    try {
      setLoading(true);
      await InAppBilling.prepare();
      const purchases = await InAppBilling.getProducts(productId);
      const receipt = await InAppBilling.buyProduct(purchases[0].productId);
      if (receipt.transactionId) {
        setPurchaseResult(`Successfully purchased: ${purchases[0].title}`);
      }
    } catch (error) {
      console.error('Purchase failed:', error);
      setPurchaseResult('Purchase failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <View>
      {purchaseItems.map(item => (
        <Button
          key={item.productId}
          title={`Buy ${item.title} for ${item.price}`}
          disabled={loading}
          onPress={() => requestPurchase(item.productId)}
        />
      ))}
      {purchaseResult && <Text>{purchaseResult}</Text>}
    </View>
  );
};

export default PaymentModule;